  "description": "An automated generative commerce platform that converts trending social media topics into merchandise using AI. Features real-time trend simulation, AI design generation, and a crowdfunding threshold mechanism."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

