export enum ProductStatus {
  DRAFT = 'DRAFT',
  CROWDFUNDING = 'CROWDFUNDING',
  FUNDED = 'FUNDED',
  PRODUCTION = 'PRODUCTION'
}

export enum ProductType {
  TSHIRT = 'T-Shirt',
  MUG = 'Mug',
  PHONE_CASE = 'Phone Case'
}

export interface Trend {
  id: string;
  topic: string;
  platform: 'TikTok' | 'Instagram' | 'Facebook';
  context: string;
  visualStyle: string;
  score: number;
}

export interface GeneratedDesign {
  imageUrl: string; // Base64 or URL
  promptUsed: string;
}

export interface Product {
  id: string;
  trendId: string;
  title: string;
  description: string;
  type: ProductType;
  designUrl: string; // The generated artwork
  votes: number;
  status: ProductStatus;
  price: number;
  createdAt: number;
  fundingProgress: number; // 0 to 100
}

export interface SystemState {
  isScanning: boolean;
  isGenerating: boolean;
  logs: string[];
}

// Mockup Base Images (hosted placeholders or consistent URLs)
export const MOCKUP_BASE_TSHIRT = "https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?q=80&w=800&auto=format&fit=crop"; 
export const MOCKUP_BASE_MUG = "https://images.unsplash.com/photo-1517260739337-6799d2df60eb?q=80&w=800&auto=format&fit=crop";

export const CROWDFUNDING_THRESHOLD = 15; // Votes needed to trigger funding
export const MAX_GENERATION_ITEMS = 3; // Items to generate per "scan"

// Prompt Engineering Templates
export const TREND_ANALYSIS_PROMPT = `
You are a trend forecasting engine for a print-on-demand business. 
Identify 3 fictional but realistic viral trends that might be popular on TikTok or Instagram right now in the US.
Focus on "memes", "catchphrases", or "aesthetic vibes" (e.g., Goblincore, Retro Futurism, Specific humorous text).
CRITICAL: Do NOT use real copyrighted characters (like Marvel, Disney), real celebrities, or trademarks. Create generic parodies or original concepts.
Return JSON format.
`;

export const DESIGN_PROMPT_PREFIX = "A high-quality, vector-style t-shirt design, isolated on a white background, flat colors, no photorealism, professional merchandise illustration: ";

import { GoogleGenAI, Type } from "@google/genai";
import { Trend, GeneratedDesign } from "../types";
import { TREND_ANALYSIS_PROMPT, DESIGN_PROMPT_PREFIX } from "../constants";

// Initialize Gemini
// Note: In a real production app, this would be proxied through a backend to hide the key.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchTrends = async (): Promise<Trend[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: TREND_ANALYSIS_PROMPT,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              topic: { type: Type.STRING },
              platform: { type: Type.STRING },
              context: { type: Type.STRING, description: "Short description of the meme/trend" },
              visualStyle: { type: Type.STRING, description: "Visual keywords for the image generator" },
              score: { type: Type.NUMBER, description: "Virality score 0-100" }
            },
            required: ["topic", "platform", "context", "visualStyle", "score"]
          }
        }
      }
    });

    const jsonStr = response.text || "[]";
    const parsedData = JSON.parse(jsonStr);

    return parsedData.map((item: any, index: number) => ({
      id: `trend-${Date.now()}-${index}`,
      ...item
    }));

  } catch (error) {
    console.error("Trend Fetch Error:", error);
    // Fallback Mock Data if API fails or Key is missing
    return [
      {
        id: 'mock-1',
        topic: 'Neon Capybara Chill',
        platform: 'TikTok',
        context: 'Capybaras relaxing in cyberpunk hot springs',
        visualStyle: 'Synthwave, Neon, Pixel Art, Cute',
        score: 95
      },
      {
        id: 'mock-2',
        topic: 'Coffee Before Chaos',
        platform: 'Instagram',
        context: 'Relatable skeleton drinking coffee while the world burns',
        visualStyle: 'Vintage Tattoo Style, Black and White, Line Art',
        score: 88
      }
    ];
  }
};

export const generateMerchDesign = async (trend: Trend): Promise<GeneratedDesign | null> => {
  try {
    const prompt = `${DESIGN_PROMPT_PREFIX} ${trend.visualStyle}. Text elements should be minimal or absent unless specified. Theme: ${trend.topic}.`;

    // Using gemini-2.5-flash-image for speed and efficiency as per guidelines
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: prompt }]
      }
    });

    let imageUrl = '';

    // Extract image from response parts
    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
          break;
        }
      }
    }

    if (!imageUrl) {
      throw new Error("No image data returned");
    }

    return {
      imageUrl,
      promptUsed: prompt
    };

  } catch (error) {
    console.error("Design Generation Error:", error);
    return null;
  }
};

import React from 'react';
import { ProductType } from '../types';
import { MOCKUP_BASE_TSHIRT, MOCKUP_BASE_MUG } from '../constants';

interface MockupViewerProps {
  type: ProductType;
  designUrl: string;
  className?: string;
}

const MockupViewer: React.FC<MockupViewerProps> = ({ type, designUrl, className = "" }) => {
  const baseImage = type === ProductType.MUG ? MOCKUP_BASE_MUG : MOCKUP_BASE_TSHIRT;

  // Adjust design placement based on product type
  // Tailwind classes for absolute positioning
  const overlayStyle = type === ProductType.MUG 
    ? "top-[30%] left-[30%] w-[40%] h-[40%]" 
    : "top-[25%] left-[28%] w-[44%] h-[50%]";

  return (
    <div className={`relative overflow-hidden rounded-lg bg-slate-900 aspect-[3/4] group ${className}`}>
      {/* Base Product Image */}
      <img 
        src={baseImage} 
        alt="Product Base" 
        className="w-full h-full object-cover opacity-90 transition-transform duration-700 group-hover:scale-105"
      />

      {/* Design Overlay */}
      <div className={`absolute ${overlayStyle} flex items-center justify-center pointer-events-none`}>
        <img 
          src={designUrl} 
          alt="Design" 
          className="max-w-full max-h-full object-contain mockup-blend opacity-90 filter drop-shadow-sm" 
          style={{ mixBlendMode: 'multiply' }}
        />
      </div>

      {/* Reflection/Lighting overlay for realism */}
      <div className="absolute inset-0 bg-gradient-to-tr from-black/20 to-transparent pointer-events-none"></div>
    </div>
