};

export default MockupViewer;

import React from 'react';
import { Product, ProductStatus } from '../types';
import MockupViewer from './MockupViewer';
import { CROWDFUNDING_THRESHOLD } from '../constants';
import { Heart, TrendingUp, ShoppingBag, CheckCircle } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  onVote: (id: string) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onVote }) => {
  const progress = Math.min((product.votes / CROWDFUNDING_THRESHOLD) * 100, 100);

  const getStatusColor = (status: ProductStatus) => {
    switch(status) {
      case ProductStatus.CROWDFUNDING: return 'bg-yellow-500 text-yellow-950';
      case ProductStatus.FUNDED: return 'bg-green-500 text-green-950';
      case ProductStatus.PRODUCTION: return 'bg-blue-500 text-blue-950';
      default: return 'bg-slate-700 text-slate-300';
    }
  };

  return (
    <div className="break-inside-avoid mb-6 relative group">
      <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden shadow-xl transition-all hover:shadow-2xl hover:border-slate-700">

        {/* Mockup Display */}
        <MockupViewer type={product.type} designUrl={product.designUrl} />

        {/* Content */}
        <div className="p-4 space-y-3">
          <div className="flex justify-between items-start">
            <h3 className="font-bold text-lg leading-tight text-white">{product.title}</h3>
            <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-wider ${getStatusColor(product.status)}`}>
              {product.status}
            </span>
          </div>

          <p className="text-xs text-slate-400 line-clamp-2">{product.description}</p>

          {/* Progress Bar for Crowdfunding */}
          <div className="space-y-1">
             <div className="flex justify-between text-xs font-medium text-slate-400">
               <span>Interest</span>
               <span>{product.votes} / {CROWDFUNDING_THRESHOLD}</span>
             </div>
             <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-purple-500 to-pink-500 transition-all duration-500"
                  style={{ width: `${progress}%` }}
                />
             </div>
          </div>

          {/* Action Area */}
          <div className="pt-2 flex items-center justify-between">
            <button 
              onClick={() => onVote(product.id)}
              disabled={product.status !== ProductStatus.DRAFT && product.status !== ProductStatus.CROWDFUNDING}
              className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-sm font-semibold transition-colors ${
                product.status === ProductStatus.FUNDED
                  ? 'bg-green-600/20 text-green-400 cursor-default'
                  : 'bg-slate-800 hover:bg-slate-700 text-white'
              }`}
            >
              {product.status === ProductStatus.FUNDED ? (
                <>
                  <CheckCircle size={16} />
                  <span>Funded</span>
                </>
              ) : (
                <>
                  <Heart size={16} className={product.votes > 0 ? "fill-pink-500 text-pink-500" : ""} />
                  <span>{product.votes} Votes</span>
                </>
              )}
            </button>

            {product.status !== ProductStatus.DRAFT && (
               <button className="p-2 text-slate-400 hover:text-white transition-colors">
                  <ShoppingBag size={20} />
               </button>
            )}
          </div>
        </div>

        {/* Trending Badge Overlay */}
        <div className="absolute top-3 right-3 bg-black/60 backdrop-blur-md border border-white/10 px-2 py-1 rounded flex items-center space-x-1 text-[10px] text-white">
           <TrendingUp size={12} className="text-purple-400" />
           <span>High Demand</span>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useEffect, useRef } from 'react';
import { Activity, Play, Terminal, Zap } from 'lucide-react';

interface ControlPanelProps {
  logs: string[];
  isScanning: boolean;
  onScan: () => void;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ logs, isScanning, onScan }) => {
  const logEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    logEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs]);

  return (
    <div className="bg-slate-900 border-b border-slate-800">
      <div className="max-w-7xl mx-auto p-4 flex flex-col md:flex-row gap-4">

        {/* Controls */}
        <div className="w-full md:w-1/3 space-y-4">
          <div>
            <h2 className="text-xl font-bold flex items-center space-x-2 text-white">
              <Zap className="text-yellow-400" />
              <span>Trend-to-Product Engine</span>
            </h2>
            <p className="text-xs text-slate-400 mt-1">
              Automated scraping & generative design pipeline.
            </p>
          </div>

          <button
            onClick={onScan}
            disabled={isScanning}
            className={`w-full flex items-center justify-center space-x-2 py-3 px-4 rounded-lg font-bold text-sm transition-all shadow-lg ${
              isScanning 
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed border border-slate-700'
                : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white shadow-purple-900/20'
            }`}
          >
            {isScanning ? (
              <>
