                <span>Analysing Social Streams...</span>
              </>
            ) : (
              <>
                <Play size={18} />
                <span>Start Scraping Cycle</span>
              </>
            )}
          </button>

          <div className="grid grid-cols-2 gap-2 text-xs text-slate-500">
             <div className="bg-slate-950 p-2 rounded border border-slate-800">
                <span className="block font-mono text-slate-300">Target</span>
                US Region / TikTok
             </div>
             <div className="bg-slate-950 p-2 rounded border border-slate-800">
                <span className="block font-mono text-slate-300">Model</span>
                Gemini 2.5 Flash
             </div>
          </div>
        </div>

        {/* Console/Log Output */}
        <div className="w-full md:w-2/3 bg-slate-950 rounded-lg border border-slate-800 font-mono text-xs p-3 h-48 overflow-hidden flex flex-col relative shadow-inner">
           <div className="absolute top-2 right-2 text-slate-600">
             <Terminal size={14} />
           </div>
           <div className="flex-1 overflow-y-auto space-y-1 custom-scrollbar">
              {logs.length === 0 && <span className="text-slate-600 opacity-50">System ready. Waiting for command...</span>}
              {logs.map((log, i) => (
                <div key={i} className="border-l-2 border-slate-800 pl-2">
                  <span className="text-slate-500">[{new Date().toLocaleTimeString()}]</span> <span className="text-green-400">{log}</span>
                </div>
              ))}
              <div ref={logEndRef} />
           </div>
        </div>

      </div>
    </div>
  );
};

export default ControlPanel;

import React, { useState, useCallback } from 'react';
import { Product, ProductStatus, ProductType, Trend } from './types';
import { fetchTrends, generateMerchDesign } from './services/geminiService';
import ControlPanel from './components/ControlPanel';
import ProductCard from './components/ProductCard';
import { CROWDFUNDING_THRESHOLD } from './constants';
import { ShoppingBag, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [isScanning, setIsScanning] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  const addLog = (message: string) => {
    setLogs(prev => [...prev, message]);
  };

  const handleScanAndGenerate = async () => {
    setIsScanning(true);
    addLog("Initializing Trend Scraper (US-Region)...");

    try {
      // 1. Fetch Trends
      addLog("Connecting to Social Media Firehose...");
      const trends = await fetchTrends();
      addLog(`Identified ${trends.length} viral signals.`);

      // 2. Process each trend
      for (const trend of trends) {
        addLog(`Processing Trend: "${trend.topic}" via Generative Engine...`);

        // Generate Art
        const design = await generateMerchDesign(trend);

        if (design) {
           addLog(`Design generated for "${trend.topic}". Compositing Mockup...`);

           const newProduct: Product = {
             id: `prod-${Date.now()}-${Math.random()}`,
             trendId: trend.id,
             title: trend.topic,
             description: trend.context,
             type: Math.random() > 0.5 ? ProductType.TSHIRT : ProductType.MUG,
             designUrl: design.imageUrl,
             votes: Math.floor(Math.random() * 5), // Random initial organic votes
             status: ProductStatus.DRAFT,
             price: 24.99,
             createdAt: Date.now(),
             fundingProgress: 0
           };

           setProducts(prev => [newProduct, ...prev]);
           addLog(`Product SKU ${newProduct.id} added to Infinite Feed.`);
        } else {
           addLog(`Failed to generate design for ${trend.topic}.`);
        }
      }

      addLog("Cycle Complete. Monitoring for new signals.");

    } catch (e) {
      console.error(e);
      addLog("System Error: Pipeline interrupted.");
    } finally {
      setIsScanning(false);
    }
  };

  const handleVote = useCallback((id: string) => {
    setProducts(prev => prev.map(p => {
      if (p.id !== id) return p;

      const newVotes = p.votes + 1;
      let newStatus = p.status;

      // Threshold Logic
      if (newVotes >= CROWDFUNDING_THRESHOLD && p.status === ProductStatus.DRAFT) {
        addLog(`THRESHOLD REACHED: Product ${p.title} has entered CROWDFUNDING phase.`);
        newStatus = ProductStatus.CROWDFUNDING;
      } else if (newVotes >= CROWDFUNDING_THRESHOLD + 10 && p.status === ProductStatus.CROWDFUNDING) {
         newStatus = ProductStatus.FUNDED;
         addLog(`FUNDED: Product ${p.title} is sent to production queue.`);
      }

      return {
        ...p,
        votes: newVotes,
        status: newStatus
      };
    }));
  }, []);

  return (
    <div className="min-h-screen bg-slate-950 text-slate-200 font-sans selection:bg-purple-500/30">

      {/* Header */}
      <nav className="border-b border-slate-800 bg-slate-950/80 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 py-3 flex items-center justify-between">
          <div className="flex items-center space-x-2">
             <div className="w-8 h-8 bg-gradient-to-br from-purple-500 to-blue-600 rounded-lg flex items-center justify-center font-bold text-white text-xl">
               T
             </div>
             <span className="font-bold text-xl tracking-tight text-white">Trend-to-Product</span>
          </div>
          <div className="flex items-center space-x-4 text-sm font-medium">
             <span className="text-slate-400 hidden sm:block">Status: <span className="text-green-400">Online</span></span>
             <button className="bg-white text-slate-950 px-4 py-2 rounded-full font-bold hover:bg-slate-200 transition-colors flex items-center space-x-2">
                <ShoppingBag size={16} />
                <span>Shop</span>
             </button>
          </div>
        </div>
      </nav>

      {/* Control Panel (Simulated Backend) */}
      <ControlPanel logs={logs} isScanning={isScanning} onScan={handleScanAndGenerate} />

      {/* Main Content Area */}
      <main className="max-w-7xl mx-auto px-4 py-8">

         <div className="flex items-center justify-between mb-8">
            <h1 className="text-3xl font-bold text-white">Live Drops</h1>
            <div className="flex space-x-2 text-sm text-slate-400">
               <span className="px-3 py-1 rounded-full border border-slate-800 bg-slate-900">Trending</span>
               <span className="px-3 py-1 rounded-full border border-slate-800 bg-slate-900">Newest</span>
            </div>
         </div>

         {/* Infinite Feed / Masonry Layout */}
         {products.length === 0 ? (
           <div className="flex flex-col items-center justify-center py-20 text-slate-500 border border-dashed border-slate-800 rounded-2xl">
             <Loader2 size={48} className={`mb-4 ${isScanning ? 'animate-spin text-purple-500' : ''}`} />
             <p className="text-lg">Feed is empty.</p>
             <p className="text-sm">Run the scraper to detect trends and generate products.</p>
           </div>
         ) : (
           <div className="columns-1 sm:columns-2 lg:columns-3 gap-6 space-y-6">
             {products.map(product => (
               <ProductCard key={product.id} product={product} onVote={handleVote} />
             ))}
           </div>
         )}
      </main>
    </div>
  );
};

export default App;

