import { Product, ProductStatus, ProductType, AppSettings } from './types';
import { fetchTrends, generateMerchDesign } from './services/geminiService';
import ControlPanel from './components/ControlPanel';
import ProductCard from './components/ProductCard';
import { CROWDFUNDING_THRESHOLD, TREND_ANALYSIS_PROMPT, DESIGN_PROMPT_PREFIX } from './constants';
import { ShoppingBag, Loader2, LayoutDashboard, Store } from 'lucide-react';

const App: React.FC = () => {
  // --- STATE ---
  const [viewMode, setViewMode] = useState<'admin' | 'store'>('admin');
  const [products, setProducts] = useState<Product[]>([]);
  const [isScanning, setIsScanning] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);

  // Backend Settings State
  const [settings, setSettings] = useState<AppSettings>({
    trendPrompt: TREND_ANALYSIS_PROMPT,
    designStylePrompt: DESIGN_PROMPT_PREFIX,
    fundingThreshold: CROWDFUNDING_THRESHOLD
  });

  const addLog = (message: string) => {
    setLogs(prev => [...prev, message]);
  };

  // --- ACTIONS ---
  const handleScanAndGenerate = async () => {
    setIsScanning(true);
    addLog(`System Init: High-Volume Mode. Threshold set to ${settings.fundingThreshold}`);

    try {
      // 1. Fetch Trends using Dynamic Prompt
      addLog("Connecting to Social Media Firehose (Scanning wide net)...");
      const trends = await fetchTrends(settings.trendPrompt);

      if (trends.length === 0) {
        addLog("Warning: No viable trends detected. Check API or Prompt settings.");
        setIsScanning(false);
        return;
      }

      addLog(`Identified ${trends.length} viral signals. Initializing Mass Production...`);

      // 2. Process trends in batches to speed up generation but avoid rate limits
      // Processing 3 trends concurrently
      const BATCH_SIZE = 3;

      for (let i = 0; i < trends.length; i += BATCH_SIZE) {
        const batch = trends.slice(i, i + BATCH_SIZE);
        const batchNum = Math.floor(i / BATCH_SIZE) + 1;
        const totalBatches = Math.ceil(trends.length / BATCH_SIZE);

        addLog(`[Batch ${batchNum}/${totalBatches}] Processing ${batch.length} trends...`);

        const results = await Promise.all(
          batch.map(async (trend) => {
             const design = await generateMerchDesign(trend, settings.designStylePrompt);
             return { trend, design };
          })
        );

        const newProducts: Product[] = [];

        for (const { trend, design } of results) {
          if (design) {
             // Create multiple variants for each trend to maximize SKU count
             const variants = [ProductType.TSHIRT, ProductType.MUG, ProductType.PHONE_CASE];

             variants.forEach((type) => {
                newProducts.push({
                  id: `prod-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
                  trendId: trend.id,
                  title: `${trend.topic} - ${type}`,
                  description: trend.context,
